def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def parse_kv_list(items: Optional[List[str]]) -> Dict[str, str]:
    out: Dict[str, str] = {}
    if not items:
        return out
    for item in items:
        if "=" not in item:
            raise ValueError(f"Invalid key=value item: {item}")
        k, v = item.split("=", 1)
        k = k.strip()
        v = v.strip()
        if not k:
            raise ValueError(f"Invalid empty key in item: {item}")
        out[k] = v
    return out


def parse_topics_arg(topics: Optional[List[str]], topics_csv: Optional[str]) -> List[str]:
    out: List[str] = []
    if topics:
        out.extend(topics)
    if topics_csv:
        out.extend([t.strip() for t in topics_csv.split(",") if t.strip()])
    # de-dup preserve order
    seen = set()
    deduped = []
    for t in out:
        if t not in seen:
            seen.add(t)
            deduped.append(t)
    return deduped


def parse_json_arg(s: Optional[str]) -> Optional[dict]:
    if s is None:
        return None
    s = s.strip()
    if not s:
        return None
    return json.loads(s)


def admin_client(args) -> KafkaAdminClient:
    kwargs = {
        "bootstrap_servers": args.bootstrap_servers,
        "client_id": args.client_id,
        "request_timeout_ms": args.request_timeout_ms,
        "api_version_auto_timeout_ms": args.api_version_auto_timeout_ms,
    }

    if args.security_protocol:
        kwargs["security_protocol"] = args.security_protocol
    if args.sasl_mechanism:
        kwargs["sasl_mechanism"] = args.sasl_mechanism
    if args.sasl_plain_username:
        kwargs["sasl_plain_username"] = args.sasl_plain_username
    if args.sasl_plain_password:
        kwargs["sasl_plain_password"] = args.sasl_plain_password
    if args.ssl_cafile:
        kwargs["ssl_cafile"] = args.ssl_cafile
    if args.ssl_certfile:
        kwargs["ssl_certfile"] = args.ssl_certfile
    if args.ssl_keyfile:
        kwargs["ssl_keyfile"] = args.ssl_keyfile
    if args.ssl_password:
        kwargs["ssl_password"] = args.ssl_password

    return KafkaAdminClient(**kwargs)


def wait_for_topics(admin: KafkaAdminClient, topics: List[str], timeout_s: int = 60, interval_s: float = 1.0) -> bool:
    deadline = time.time() + timeout_s
    remaining = set(topics)
    while time.time() < deadline:
        try:
            existing = set(admin.list_topics())
        except Exception:
            existing = set()
        remaining = set(topics) - existing
        if not remaining:
            return True
        time.sleep(interval_s)
    return False


def cmd_create_topics(args) -> int:
    topics = parse_topics_arg(args.topic, args.topics)
    if not topics:
        eprint("No topics specified. Use --topic or --topics.")
        return 2

    topic_configs = parse_kv_list(args.config)
    if args.config_json:
        topic_configs.update(parse_json_arg(args.config_json) or {})

    new_topics = []
    for t in topics:
        new_topics.append(
            NewTopic(
                name=t,
                num_partitions=args.partitions,
                replication_factor=args.replication_factor,
                topic_configs=topic_configs if topic_configs else None,
            )
        )

    admin = admin_client(args)
    try:
        fs = admin.create_topics(new_topics=new_topics, validate_only=args.validate_only)
        errors = 0
        for name, f in fs.items():
            try:
                f.result(timeout=args.op_timeout_s)
                print(json.dumps({"topic": name, "status": "created" if not args.validate_only else "validated"}))
            except TopicAlreadyExistsError:
                if args.if_not_exists:
                    print(json.dumps({"topic": name, "status": "exists"}))
                else:
                    errors += 1
                    eprint(json.dumps({"topic": name, "error": "TopicAlreadyExists"}))
            except KafkaError as ke:
                errors += 1
                eprint(json.dumps({"topic": name, "error": ke.__class__.__name__, "message": str(ke)}))
            except Exception as ex:
                errors += 1
                eprint(json.dumps({"topic": name, "error": ex.__class__.__name__, "message": str(ex)}))

        if args.wait and not args.validate_only:
            ok = wait_for_topics(admin, topics, timeout_s=args.wait_timeout_s, interval_s=args.wait_interval_s)
            if not ok:
                errors += 1
                eprint(json.dumps({"error": "WaitTimeout", "missing_topics": list(set(topics) - set(admin.list_topics()))}))

        return 1 if errors else 0
    finally:
        try:
            admin.close()
        except Exception:
            pass


def cmd_increase_partitions(args) -> int:
    topics = parse_topics_arg(args.topic, args.topics)
    if not topics:
        eprint("No topics specified. Use --topic or --topics.")
