def cmd_alter_configs(args) -> int:
    topics = parse_topics_arg(args.topic, args.topics)
    if not topics:
        eprint("No topics specified. Use --topic or --topics.")
        return 2

    configs = parse_kv_list(args.config)
    if args.config_json:
        configs.update(parse_json_arg(args.config_json) or {})

    if not configs and not args.delete_config:
        eprint("No configs specified. Use --config/--config-json and/or --delete-config.")
        return 2

    delete_keys = args.delete_config or []

    admin = admin_client(args)
    try:
        resources = []
        for t in topics:
            entry = {"resource_type": 2, "resource_name": t, "configs": {}}
            for k, v in configs.items():
                entry["configs"][k] = v
            for k in delete_keys:
                entry["configs"][k] = None
            resources.append(entry)

        fs = admin.alter_configs(config_resources=resources)
        errors = 0
        for res, f in fs.items():
            try:
                f.result(timeout=args.op_timeout_s)
                print(json.dumps({"resource": str(res), "status": "configs_altered"}))
            except UnknownTopicOrPartitionError:
                errors += 1
                eprint(json.dumps({"resource": str(res), "error": "UnknownTopicOrPartition"}))
            except KafkaError as ke:
                errors += 1
                eprint(json.dumps({"resource": str(res), "error": ke.__class__.__name__, "message": str(ke)}))
            except Exception as ex:
                errors += 1
                eprint(json.dumps({"resource": str(res), "error": ex.__class__.__name__, "message": str(ex)}))
        return 1 if errors else 0
    finally:
        try:
            admin.close()
        except Exception:
            pass


def cmd_describe_topics(args) -> int:
    topics = parse_topics_arg(args.topic, args.topics)
